<template><view class="page"><view class="row"><view><view class="title">庆喜儿控制台</view><view class="subtitle">唤醒词：阿西</view></view><StatusBadge :text="summary.onlineText" :ok="status?.online"/></view><AppCard title="设备状态"><view class="grid"><view><view class="metric">{{summary.batteryText}}</view><view class="muted">电量</view></view><view><view class="metric">{{summary.modeText}}</view><view class="muted">当前模式</view></view><view><view class="metric">{{summary.personaText}}</view><view class="muted">人格</view></view><view><view class="metric">{{status?.temperature||0}}℃</view><view class="muted">胸口温度</view></view></view></AppCard><AppCard title="快捷控制"><view class="grid"><button class="btn secondary" @click="command('heartbeat')">模拟心跳</button><button class="btn secondary" @click="command('heat')">恒温</button><button class="btn secondary" @click="go('/pages/speech-settings/index')">语音设置</button><button class="btn secondary" @click="go('/pages/device-bind/index')">配网绑定</button></view></AppCard><AppCard title="功能入口"><view class="list-item" @click="go('/pages/parent-control/index')">家长控制</view><view class="list-item" @click="go('/pages/custom-content/index')">自定义内容</view><view class="list-item" @click="go('/pages/voice-clone/index')">声音克隆</view><view class="list-item" @click="go('/pages/mood-report/index')">心情周报</view></AppCard></view></template>
<script setup lang="ts">import{computed}from'vue';import{onShow}from'@dcloudio/uni-app';import AppCard from'@/components/AppCard.vue';import StatusBadge from'@/components/StatusBadge.vue';import{useDeviceStore}from'@/stores/device';import{deviceSummary}from'@/view-models';import{qingxierApi}from'@/services/api';const store=useDeviceStore();const status=computed(()=>store.status);const summary=computed(()=>deviceSummary(status.value));onShow(()=>store.load());const go=(url:string)=>uni.navigateTo({url});async function command(type:string){if(!store.currentId)return;await qingxierApi.command(store.currentId,{commandType:type,payload:{enabled:true},needAck:true});uni.showToast({title:'指令已发送'});}</script>
